sp_widget.client_script:
function ($scope, spModal, spUtil, $timeout) {
	var c = this;
	var TOOL_BAR_CONST;
	var isCustom = false;
	// call main function
	main();
	function main(){
		TOOL_BAR_CONST = _loadTollBarConstants();
		c.data.zoomPercents = _loadZoomPercents();
		_initOnLoadComplete();
	}
	function _loadZoomPercents(value) {
		var lZoomPercents = [
			{value: "1", text: "100%"},
			{value: ".75", text: "75%"},
			{value: ".50", text: "50%"},
			{value: ".25", text: "25%"},
			{value: "tree", text: c.data.messages["Tasker - Entire Tree"]},
			{value: "custom", text: c.data.messages["Tasker - Custom Zoom"]}
		];
		return lZoomPercents;
	}

	function _getSelectedBasedOnValue(value){
		var index = -1;
		for (var i = 0; i < c.data.zoomPercents.length; i++) {
			if(c.data.zoomPercents[i].value==value){
				index = i;
				break;
			}
		}
		$scope.data.selectedValue = c.data.zoomPercents[index];
	}

	$scope.shouldShow = function(zoomPct){
		var show = false;
		if(zoomPct.value=="custom")
			show = isCustom;
		else 
			show = true;

		return show;
	}

	// STRY0117600
	function _loadTollBarConstants() {
		var oTOOL_BAR_CONST = {
		};
		return oTOOL_BAR_CONST;
	}	

	function _setSelectPercent(scale){
		var selectPercent = "";
		var scaleNumeric = 1.0;
		isCustom = false;
		scaleNumeric = Number.parseFloat(scale);
		c.data.settings.diagramScale = scaleNumeric;

		switch(scaleNumeric){
			case 1: case 0.75: case 0.5: case 0.25:
				selectPercent = scaleNumeric;
				break;
			default: 
				// if the viewport height or the width is within 20 pixels of the documengBounds height or width, set to tree
				// we are checking both height and width to avoid checking the orientation, but we could check orientation and then only check one or the other
				// the only challenge might be that the header has orientation and the footer has the size setting
				if(c.widget.diagram && 
					 c.widget.diagram.viewportBounds && 
					 c.widget.diagram.documentBounds){
					if(
						(((c.widget.diagram.viewportBounds.width + 5)>=
							c.widget.diagram.documentBounds.width) &&
						 ((c.widget.diagram.viewportBounds.width - 5)<=
							c.widget.diagram.documentBounds.width)) ||
						(((c.widget.diagram.viewportBounds.height + 5)>=
							c.widget.diagram.documentBounds.height) &&
						 ((c.widget.diagram.viewportBounds.height - 5)<=
							c.widget.diagram.documentBounds.height))
					)
					{
						// used to select tree from the dropdown
						selectPercent="tree";
						// used to save tree back to the server
						c.data.isTree=true;
					} else {
						// used to add custom to the drop down and select it
						selectPercent="custom";
						// used to save the custom value back on the server
						isCustom = true;
					}
				}
		}
		_getSelectedBasedOnValue(selectPercent);
	}

	// new to trap diagram changes and reset the selected and zoom percent
	c.widget.resetDiagram = function(){
		// set to true to force an update of the select percent
		// set to false once the selectPercent is updated
		if(c.data.isTree){
			$scope.zoomToFullTree();
			_setSelectPercent(c.widget.diagram.scale);			
		} else if(c.data.settings.diagramScale){
			_setSelectPercent(c.data.settings.diagramScale);			
		}	
	}

	// STRY0117945 - set custom scale or reset to a zoomPercent
	c.widget.scale = function(scale){
		c.data.isTree=false;
		if(c.data.settings.diagramScale != scale){
			// save previous select percent in order to save "custom"
			var previousZoomPct = c.data.settings.diagramScale;
			_setSelectPercent(scale);
			$timeout(
				function(){ 
					// this function ensures that when the user custom zooms it gets saved
					if(previousZoomPct != c.data.settings.diagramScale){
						$scope.$apply(); 
						// save the custom zoom number
						$scope.data.settings.diagramScale=scale;
						$scope.data.percentChanged = true; 
						spUtil.update($scope).then(function() {
							return;
						});
					}
				},
				200);
		}
	}

	// NOTE: this is not needed when control is loaded from the server
	//       It was left in for cases where developers would want to load from client
	//       this emits to the parent when the control completes building
	function _initOnLoadComplete(){
		// only push resize when footer is done loading
		if(c.data.iconGroup == "footer"){
			angular.element(document).ready(function () {
				// tell the wrapping widget that the toolbar has finished loading
				$scope.$emit('tasker-tree-footer-toolbar.initComplete');
				// set the selected precent
				_setSelectPercent(c.data.settings.diagramScale);
			});

		}
	}

	// Switch to Horizontal
	$scope.switchToHorizontal = function() {
		$scope.$emit('$tasker-tree-toolbar-icons.switchToHorizontal');
		$scope.data.settings.treeOrientation="Horizontal";
		$scope.data.orientationChanged = true; 
		spUtil.update($scope);
	};

	// Switch to Vertical
	$scope.switchToVertical = function() {
		$scope.$emit('$tasker-tree-toolbar-icons.switchToVertical');
		$scope.data.settings.treeOrientation="Vertical";
		$scope.data.orientationChanged = true; 
		spUtil.update($scope);
	};

	// add the selected node to the favorites for the user
	$scope.addToFavorites = function() {
		var selectedNode = c.widget.diagram.findNodeForKey(c.widget.parentSelectedId);
		c.widget.diagram.commandHandler.resetZoom($scope.data.settings.diagramScale);
		c.widget.diagram.centerRect(selectedNode.actualBounds);			

		$scope.data.favoriteChanged = true; 
		$scope.data.settings.favorite = {
			value: c.widget.parentSelectedId,
			topId: c.widget.currentTop};
		spUtil.update($scope).then(function() {
			// submit favorite change back to server
			return;
		});
	};

		// Zoom to Favorite
	$scope.zoomToFavorite = function() {
		// STRY0121023
		if(c.data.settings.favorite.value && c.data.settings.favorite.value != c.widget.parentSelectedId){
			var newSelectedId = c.data.settings.favorite.value;
			var favoriteOUNode = c.widget.diagram.findNodeForKey(c.data.settings.favorite.value);
			if(favoriteOUNode){
				c.widget.parentSelectedId = c.data.settings.favorite.value;
				c.widget.diagram.select(favoriteOUNode);
			} else {
				// if user selected to stop prompt, don't show again
				var changeTree = true;
				if(!c.data.settings.favoriteStopPrompt){
					changeTree =_promptChangeTree("favoriteOU", newSelectedId);
				}
			}
		}

	};

		// Zoom to Default OU
	$scope.zoomToDefaultOU = function() {
		// STRY0121017
		if(c.data.settings.defaultOU.value && c.data.settings.defaultOU.value != c.widget.parentSelectedId){
			var newSelectedId = c.data.settings.defaultOU.value;

			var defaultOUNode = c.widget.diagram.findNodeForKey(c.data.settings.defaultOU.value);
			if(defaultOUNode){
				c.widget.parentSelectedId = c.data.settings.defaultOU.value;
				c.widget.diagram.select(defaultOUNode);
			} else {
				// if user selected to stop prompt, don't show again
				var changeTree = true;
				if(!c.data.settings.defaultStopPrompt){
					changeTree = _promptChangeTree("defaultOU", newSelectedId);
				}
			}
		}
	};

	// STRY0121023 - STRY0121017
	// raise to OU Tree change to different tree (represented by the OU provided)									
	function _parentChangeDiagram(selectedId){
		var params = {};
		params.sys_id = selectedId;
		$scope.$emit('tasker-tree-footer-toolbar.changeTree',params);
	}

	// STRY0121023 - STRY0121017
	function _promptChangeTree(changeType, new_ou_id){
		var title = c.data.messages["Tasker - Leave Current Organization Tree?"];

		var modalSelection = {};
		spModal.open({
			title: title,
			widgetInput: {
				favoriteOU: (changeType=="favoriteOU"),
				defaultOU: (changeType=="defaultOU")
			},
			backdrop: 'static',
			widget: 'tasker_modal_org_change_tree_confirm',
			size: 'md',
			shared: modalSelection,
			buttons: [],
			footerStyle: {
				'display': 'none'
			}
		}).then(function(response) {
			// here when a primary button (continue to new tree)
			if(modalSelection.confirm){
				if(modalSelection.stopPrompt){
					// post back here to not show again
					if(changeType == "favoriteOU"){
						c.data.settings.favoriteStopPrompt = true;
						$scope.data.favoriteStopPrompt = true;
					} else if(changeType == "defaultOU"){
						c.data.settings.defaultStopPrompt = true;
						$scope.data.defaultStopPrompt = true;
					}
					spUtil.update($scope);			
				}
				// change to new tree
				_parentChangeDiagram(new_ou_id);

			}
		}, function() {
			// cancel selected, do not change tree
		});
	}

	// Zoom to Top OU
	$scope.zoomToTop = function() {
		// STRY0074663 Only rebroadcast if the node changed
		if(c.widget.currentTop && c.widget.currentTop != c.widget.parentSelectedId){
			c.widget.parentSelectedId = c.widget.currentTop;
			// need to emit selection change to current top
			// Select the node using the sys_id parameter supplied.
			var node_select = c.widget.diagram.findNodeForKey(c.widget.parentSelectedId);
			c.widget.diagram.select(node_select);
		}			
	}

	// Zoom to Selected
	$scope.zoomToSelected = function() {
		_zoomToSelected();
		if(Number.parseFloat(c.data.settings.diagramScale)!=1.0){
			$scope.data.settings.diagramScale=1.0;
			$scope.data.percentChanged = true; 
			spUtil.update($scope).then(function() {
				// submit percent change back to server
				return;
			});
		}
	};

	// Zoom to full tree
	$scope.zoomToFullTree = function() {
		if(!c.data.isTree){
			$scope.data.isTree=true;
			c.data.isTree=true;
			$scope.data.percentChanged = true; 
			spUtil.update($scope);	
		}
		// submit percent change back to server
		c.widget.diagram.zoomToRect(c.widget.diagram.documentBounds);
		// reset scale after saving tree
		c.data.settings.diagramScale = c.widget.diagram.scale;
		// set the selected precent
		_getSelectedBasedOnValue("tree");
	};

	// Zoom to Percentage
	$scope.zoomToPercent = function() {
		var lScale;
		if($scope.data.selectedValue) {
			switch($scope.data.selectedValue.value){
				case "tree":
					$scope.zoomToFullTree();
					break;
				case "custom":  // skip, no post back
					break;
				default:
					$scope.data.settings.diagramScale=Number.parseFloat($scope.data.selectedValue.value);
					$scope.data.percentChanged = true; 
					spUtil.update($scope).then(function() {
						// submit percent change back to server
						var selectedNode = c.widget.diagram.findNodeForKey(c.widget.parentSelectedId);
						c.widget.diagram.commandHandler.resetZoom($scope.data.settings.diagramScale);
						c.widget.diagram.centerRect(selectedNode.actualBounds);
						// set the selected precent
						_setSelectPercent(c.data.settings.diagramScale);
					});
					break;
			}			
		}

	};
	function _zoomToSelected(){
		var selectedNode = c.widget.diagram.findNodeForKey(c.widget.parentSelectedId);
		c.widget.diagram.commandHandler.resetZoom(1.0);
		c.widget.diagram.centerRect(selectedNode.actualBounds);
	}

}

